// Helper to create date in IST (UTC+5:30)
function istDate(daysAgo: number = 0, hoursAgo: number = 0): Date {
  const now = new Date();
  const istOffset = 5.5 * 60 * 60 * 1000;
  const utc = now.getTime() + now.getTimezoneOffset() * 60 * 1000 + istOffset;
  const d = new Date(utc - daysAgo * 86400000 - hoursAgo * 3600000);
  return d;
}

