async function seedStations() {
  console.log('Seeding charging stations...');
  
  // Delete existing data
  await db.chargingStation.deleteMany();
  await db.chargingAlert.deleteMany();
  await db.routeAnalysis.deleteMany();
  await db.investmentOpportunity.deleteMany();
  await db.chargingDesert.deleteMany();

  // Insert stations
  for (const s of stations) {
    await db.chargingStation.create({ data: s });
  }
  console.log(`Seeded ${stations.length} charging stations`);
}

